    return (
      <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }} key={'item_' + gallery}>
        <LinkButton
          onClick={() => navigate('/collections/' + gallery.toLowerCase().trim().replace(/\s/g, ''))}
          color='inherit'
          key={'button_' + gallery}
        >
          {gallery}
        </LinkButton>
      </Grid>
    )
  }

  React.useEffect(() => {
    collections.forEach((gallery) => {
      setNavigation(navigation => [...navigation, item(gallery)])
    })
  }, [navigate])

  return (
    <>
      <AppBar
        position='static'
        color='inherit'
        sx={{
          boxShadow: '0px 0px 0px #e3e3e3',
